function solve(weight: number[]): number {
    let count = 0;
    let currentMax: number | null = null;

    for (const w of weight) {
        if (currentMax === null) {
            currentMax = w;
        } else {
            if (w > currentMax) {
                currentMax = w;
            }
            if (w < currentMax) {
                count++;
                currentMax = null;
            }
